const vm = $input.first().json.body || $input.first().json;

function formatPhone(p) {
  if (!p) return 'Unknown';
  const digits = String(p).replace(/\D/g, '');
  if (digits.length === 11 && digits.startsWith('1')) {
    return `(${digits.slice(1, 4)}) ${digits.slice(4, 7)}-${digits.slice(7)}`;
  }
  if (digits.length === 10) {
    return `(${digits.slice(0, 3)}) ${digits.slice(3, 6)}-${digits.slice(6)}`;
  }
  return String(p);
}

function formatTime(iso) {
  if (!iso) return 'Just now';
  const d = new Date(iso);
  return d.toLocaleString('en-US', {
    timeZone: 'America/New_York',
    month: 'short', day: 'numeric',
    hour: 'numeric', minute: '2-digit', hour12: true
  }) + ' ET';
}

const caller = formatPhone(vm.from);
const callerRaw = vm.from || '';
const received = formatTime(vm.timestamp);
const transcription = (vm.transcription || '_No transcription available_').trim();
const recordingUrl = vm.recordingUrl || '';
const preview = transcription.length > 140 ? transcription.slice(0, 140) + '…' : transcription;

const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: '📞 New B2B Voicemail' }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*From:*\n${caller}` },
      { type: 'mrkdwn', text: `*Received:*\n${received}` }
    ]
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Transcription:*\n>${transcription.replace(/\n/g, '\n>')}`
    }
  }
];

// Action buttons (Listen URL + Bounce interactive)
const actionElements = [];
if (recordingUrl) {
  actionElements.push({
    type: 'button',
    text: { type: 'plain_text', text: '🎧 Listen to recording' },
    url: recordingUrl,
    action_id: 'listen_vm'
  });
}
if (callerRaw) {
  actionElements.push({
    type: 'button',
    text: { type: 'plain_text', text: '↪️ Bounce to Consumer Line' },
    style: 'primary',
    action_id: 'bounce_to_consumer',
    value: callerRaw,
    confirm: {
      title: { type: 'plain_text', text: 'Place callback?' },
      text: { type: 'mrkdwn', text: `This will call *${caller}* from your consumer line (352-505-7582) and play the recorded bounce message. Caller ID will show as your consumer line.` },
      confirm: { type: 'plain_text', text: 'Yes, call now' },
      deny: { type: 'plain_text', text: 'Cancel' }
    }
  });
}
if (actionElements.length) {
  blocks.push({ type: 'actions', elements: actionElements });
}

const slackBody = JSON.stringify({
  channel: 'b2b-voicemails',
  username: 'B2B VM Bot',
  text: `📞 New B2B voicemail from ${caller}: ${preview}`,
  blocks: blocks
});

return [{ json: { slackBody } }];
